def test_canonical_json_and_hash_json():
    value = {"b": 2, "a": ["é"]}
    assert canonical_json(value) == '{"a":["\\u00e9"],"b":2}'
    expected = hashlib.sha256(json.dumps(value, sort_keys=True, separators=(",", ":"), ensure_ascii=True).encode("utf-8")).hexdigest()
